using Microsoft.AspNetCore.Http;
using System.IdentityModel.Tokens.Jwt;

public class JwtAuthenticationMiddleware : IMiddleware
{
    private readonly ILogger<JwtAuthenticationMiddleware> _logger;

    public JwtAuthenticationMiddleware(ILogger<JwtAuthenticationMiddleware> logger)
    {
        _logger = logger;
    }

    public async Task InvokeAsync(HttpContext context, RequestDelegate next)
    {
        var token = context.Request.Headers["Authorization"].FirstOrDefault()?.Split(" ").Last();

        if (token != null)
        {
            try
            {
                var jwtSecurityToken = new JwtSecurityToken(token);

                // Verify the signature of the token
                var validationParameters = new TokenValidationParameters
                {
                    ValidateIssuerSigningKey = true,
                    IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes("your_secret_key")),
                    ValidateIssuer = false,
                    ValidateAudience = false,
                    ValidateLifetime = true,
                    ClockSkew = TimeSpan.Zero
                };

                var principal = new JwtSecurityTokenHandler().ValidateToken(token, validationParameters);

                // Populate the HttpContext user with the claims from the token
                context.User = principal;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Failed to validate JWT token");
            }
        }

        await next(context);
